mapper.select:
SELECT COUNT(*)
FROM notice
WHERE id = #{noticeId}

mapper.update:
UPDATE notice_receipts
SET read_at = NOW()
WHERE notice_id = #{noticeId}
  AND user_id = #{userId}
  AND read_at IS NULL

mapper.select:
SELECT nr.id, nr.notice_id, nr.user_id, nr.delivered_at, nr.read_at, n.title AS notice_title FROM notice_receipts nr JOIN notice n ON n.id = nr.notice_id WHERE nr.user_id = #{userId}
AND nr.read_at IS NULL
ORDER BY nr.delivered_at DESC
